// Example seed script using Prisma
import { PrismaClient } from '@prisma/client'
import sectorsData from './sectors.json'

const prisma = new PrismaClient()

async function main() {
  for (const sector of sectorsData.seed_data.m_sektor_industri) {
    await prisma.m_sektor_industri.upsert({
      where: { nama_sektor: sector.nama_sektor },
      update: {},
      create: sector,
    })
  }
  console.log('✅ Seeded m_sektor_industri successfully')
}

main()
  .catch((e) => {
    console.error(e)
    process.exit(1)
  })
  .finally(async () => {
    await prisma.$disconnect()
  })
